interface.signature:
{
  stepType: "invoke-workflow",
  config: {
    workflowsToInvoke: string,        // Variable reference e.g. "{{techniques}}"
    variableMapping: {                 // Map parent variables to child variable names (ONLY mapped vars passed)
      [childVarName: string]: string   // e.g., session_topic: "{{topic}}" (child uses {{parent.session_topic}}, gets from parent's {{topic}})
    },
    expectedOutputVariable: string,    // Variable name to read from each child (e.g., "generated_ideas")
    aggregateInto: string,             // Parent variable to append child outputs (e.g., "captured_ideas")
    completionCondition: {
      type: "all-complete"             // Wait for all children to reach status = completed
    }
  }
}

interface.example:
// Brainstorming Step 2 Configuration (Task 4)
{
  stepType: "invoke-workflow",
  config: {
    workflowsToInvoke: "{{techniques}}",  // From Step 1's outputVariables.techniques
    variableMapping: {
      session_topic: "{{topic}}",    // Child uses {{parent.session_topic}}, gets from parent's {{topic}}
      stated_goals: "{{goals}}"      // Child uses {{parent.stated_goals}}, gets from parent's {{goals}}
    },
    expectedOutputVariable: "generated_ideas",
    aggregateInto: "captured_ideas",
    completionCondition: { type: "all-complete" }
  }
}

// How it works:
// 1. Parent Step 1 outputVariables: { topic: "...", goals: "...", techniques: [...] }
// 2. Parent Step 2 reads techniques array, creates child executions
// 3. For each child: variableMapping creates parent.session_topic = parent.topic, parent.stated_goals = parent.goals
// 4. Child workflow initialPrompt: "Topic: {{parent.session_topic}}, Goals: {{parent.stated_goals}}"
// 5. Child completes, parent reads child.variables.generated_ideas and appends to parent.variables.captured_ideas

interface.signature:
parentExecutionId: uuid | null,  // FK to workflow_executions.id (self-referencing)
// When null: top-level workflow
// When set: child workflow execution

executedSteps: {
  [stepNumber: string]: {
    status: "completed" | "in-progress" | "failed",
    startedAt: string,      // ISO 8601 timestamp (NEW in Story 2.3)
    completedAt: string | null,  // ISO 8601 timestamp (NEW in Story 2.3)
    output: any
  }
}

{
  variableName: string,
  valueType: "object",  // NEW in Story 2.3 (was only string, number, boolean, array)
  valueSchema: {
    type: "object",
    required?: string[],              // Required property names
    properties: {
      [key: string]: {
        type: "string" | "number" | "boolean" | "array"  // Shallow only
      }
    },
    additionalProperties?: {          // For dynamic keys (e.g., mind mapping branches)
      type: "array",
      items: { type: "string" }
    }
  }
}

{
  stepType: "ask-user-chat",
  config: {
    generateInitialMessage: boolean,  // NEW in Story 2.3
    initialPrompt: string,            // NEW in Story 2.3 - system prompt for generation
    systemPrompt: string,             // Existing - agent instructions
    tools: [...],                     // Mastra tools
    completionCondition: {...}        // Existing
  }
}
// When generateInitialMessage = true:
// 1. Agent calls generate([], { system: resolvedInitialPrompt })
// 2. Resolves {{parent.variable}} references in initialPrompt
// 3. Returns generated message as first assistant message
// 4. User sees dynamic first question tailored to their topic

metadata: {
  layoutType: "wizard" | "artifact-workbench" | "dialog",  // "dialog" is NEW in Story 2.3
  icon?: string,
  color?: string,
  recommendedFor?: string[],
  estimatedDuration?: string,
  // ... other metadata
}

// Layout Types:
// - "wizard": Linear flow with stepper, no split view, step content rendered directly
// - "artifact-workbench": Split view with Timeline on left + ArtifactPreview on right
// - "dialog": Modal overlay on top of parent workflow, step content in dialog body

// layoutType = "dialog":
// - Renders as modal overlay on top of parent workflow
// - Parent workflow visible behind with dimmed overlay
// - Dialog body renders current step's step type component
// - Used by all technique workflows (SCAMPER, Six Hats, etc.)

// StepRenderer: Returns pure step content based on stepType (no layout concerns)
interface StepRendererProps {
  step: WorkflowStep,
  execution: WorkflowExecution
}

// Returns step component based on stepType:
// - "ask-user-chat" → AskUserChatInterface
// - "invoke-workflow" → ActionList (child workflow execution list)
// - "ask-user" → AskUserForm
// - "display-output" → DisplayOutput
// - "execute-action" → ExecuteActionStatus
// Does NOT wrap in Timeline or any layout component
// Does NOT handle navigation or mode switching

// Component Hierarchy:
// WorkflowLayoutRenderer (routes to correct layout based on metadata.layoutType)
//   ├─ WizardLayout (linear steps, stepper at top, no split view)
//   ├─ ArtifactWorkbenchLayout (split view: Timeline left + ArtifactPreview right)
//   └─ DialogLayout (modal overlay)

// WorkflowLayoutRenderer: Top-level router
interface WorkflowLayoutRendererProps {
  workflow: Workflow,
  execution: WorkflowExecution
}
// 1. Renders StepRenderer once to get step content
// 2. Passes step content to appropriate layout based on metadata.layoutType
// 3. Layout decides how to present step (Timeline wrapper or direct)

// ArtifactWorkbenchLayout: Self-contained split view
interface ArtifactWorkbenchLayoutProps {
  execution: WorkflowExecution,
  stepContent: React.ReactNode  // Step component passed from renderer
}
// Renders:
// - Left: Timeline (manages focused/browse modes, wraps stepContent)
// - Right: ArtifactPreview (internally created from execution)
// NO artifactContent prop - layout handles it internally!

// Timeline: Specific to artifact-workbench layout only
interface TimelineProps {
  mode: "focused" | "browse",
  steps: WorkflowStep[],
  currentStep: number,
  onModeChange: (mode: "focused" | "browse") => void,
  children: React.ReactNode  // Step content from layout
}
// Focused mode: Renders children (step content) at 100% height
// Browse mode: Shows accordion of all steps, clicking switches to focused

// WizardLayout: Linear flow (no Timeline)
interface WizardLayoutProps {
  execution: WorkflowExecution,
  stepContent: React.ReactNode
}
// Renders: Stepper at top + step content directly (no Timeline wrapper)

// DialogLayout: Modal overlay (no Timeline)
interface DialogLayoutProps {
  execution: WorkflowExecution,
  stepContent: React.ReactNode,
  onClose: () => void
}
// Renders: Step content in modal dialog with Return to Parent button

interface ActionListProps {
  childExecutions: Array<{
    id: string,
    workflowId: string,
    workflowName: string,
    status: "pending" | "running" | "completed" | "failed",
    capturedIdeasCount?: number
  }>,
  onExecute: (executionId: string) => void,  // Opens dialog for child workflow
  loading: boolean
}

interface DialogLayoutProps {
  execution: WorkflowExecution,  // Child workflow execution
  stepContent: React.ReactNode,  // Step component from StepRenderer
  onClose: () => void            // Close dialog (pauses child execution)
}
// Dialog renders:
// 1. Optional stepper at top (for multi-step techniques like Mind Mapping 4 steps)
// 2. stepContent passed as children (e.g., AskUserChatInterface, ActionList)
// 3. Return to Parent button in footer
// 4. Parent workflow visible behind with dimmed overlay
// 5. NO Timeline wrapper - step content rendered directly in dialog

// Timeline: Container for step navigation (ONLY used in artifact-workbench layout)
interface TimelineProps {
  mode: "focused" | "browse",
  steps: WorkflowStep[],
  currentStep: number,
  onModeChange: (mode: "focused" | "browse") => void,
  children: React.ReactNode  // Step content passed from ArtifactWorkbenchLayout
}
// Behavior:
// - Focused mode: Renders children (step content) at 100% height, other steps hidden
// - Browse mode: Shows accordion of all steps, clicking step switches to focused mode
// - Toggle button in header switches between modes
// - NOT used by wizard or dialog layouts - specific to artifact-workbench only

// Browse Mode Component (Accordion for Navigation)
interface TimelineBrowseViewProps {
  steps: WorkflowStep[],
  executedSteps: Record<string, ExecutedStepInfo>,
  currentStep: number,
  onStepClick: (stepNumber: number) => void  // Switches to focused mode
}
// Renders accordion with all steps showing timestamps
// Clicking AccordionTrigger calls onStepClick which switches to focused mode
// Accordion is for navigation, not just expanding/collapsing in place

type ExecutedStepInfo = {
  status: "completed" | "in-progress" | "failed" | "pending",
  startedAt?: string,      // ISO 8601 timestamp
  completedAt?: string,    // ISO 8601 timestamp
  duration?: string        // Calculated from startedAt/completedAt
}
